mapper.sql:
WHERE g.status = 1 AND g.audit_status = 1 AND g.is_deleted = 0
AND g.merchant_id = #{query.merchantId}
AND (g.goods_name LIKE CONCAT('%', #{query.keyword}, '%') OR g.keywords LIKE CONCAT('%', #{query.keyword}, '%'))
AND g.cate_id IN
#{cateId}

mapper.select:
SELECT COUNT(*) FROM ( SELECT g.goods_id FROM tb_goods g LEFT JOIN tb_goods_sku s ON s.goods_id = g.goods_id AND s.status = 1 AND s.is_deleted = 0
GROUP BY g.goods_id
HAVING 1 = 1
AND MIN(s.price) >= #{query.minPrice}
AND MIN(s.price) <= #{query.maxPrice}
HAVING COUNT(s.sku_id) > 0
AND COUNT(s.sku_id) > 0
) tmp

SELECT g.goods_id AS goodsId, g.cate_id AS categoryId, c.cate_name AS categoryName, g.merchant_id AS merchantId, m.merchant_name AS merchantName, g.goods_name AS goodsName, g.goods_intro AS goodsIntro, g.goods_pic AS goodsPic, MIN(s.sku_id) AS defaultSkuId, MIN(s.price) AS displayPrice, COALESCE(SUM(GREATEST(s.stock - s.lock_stock, 0)), 0) AS totalStock, g.sell_count AS sellCount, g.comment_count AS commentCount, g.goods_score AS goodsScore FROM tb_goods g LEFT JOIN tb_category c ON c.cate_id = g.cate_id LEFT JOIN tb_merchant m ON m.merchant_id = g.merchant_id LEFT JOIN tb_goods_sku s ON s.goods_id = g.goods_id AND s.status = 1 AND s.is_deleted = 0
GROUP BY g.goods_id, g.cate_id, c.cate_name, g.merchant_id, m.merchant_name, g.goods_name, g.goods_intro, g.goods_pic, g.sell_count, g.comment_count, g.goods_score
HAVING 1 = 1
AND MIN(s.price) >= #{query.minPrice}
AND MIN(s.price) <= #{query.maxPrice}
AND COUNT(s.sku_id) > 0
HAVING COUNT(s.sku_id) > 0
ORDER BY ${orderBy} LIMIT #{offset}, #{query.pageSize}

SELECT COUNT(*) FROM ( SELECT g.goods_id FROM tb_goods g LEFT JOIN tb_goods_sku s ON s.goods_id = g.goods_id AND s.status = 1 AND s.is_deleted = 0 WHERE g.merchant_id = #{merchantId}
AND (g.goods_name LIKE CONCAT('%', #{keyword}, '%') OR g.keywords LIKE CONCAT('%', #{keyword}, '%'))
AND g.status = 1 AND g.audit_status = 1 AND g.is_deleted = 0 GROUP BY g.goods_id HAVING COUNT(s.sku_id) > 0 ) tmp

SELECT g.goods_id AS goodsId, g.cate_id AS categoryId, c.cate_name AS categoryName, g.merchant_id AS merchantId, m.merchant_name AS merchantName, g.goods_name AS goodsName, g.goods_intro AS goodsIntro, g.goods_pic AS goodsPic, MIN(s.sku_id) AS defaultSkuId, MIN(s.price) AS displayPrice, COALESCE(SUM(GREATEST(s.stock - s.lock_stock, 0)), 0) AS totalStock, g.sell_count AS sellCount, g.comment_count AS commentCount, g.goods_score AS goodsScore FROM tb_goods g LEFT JOIN tb_category c ON c.cate_id = g.cate_id LEFT JOIN tb_merchant m ON m.merchant_id = g.merchant_id LEFT JOIN tb_goods_sku s ON s.goods_id = g.goods_id AND s.status = 1 AND s.is_deleted = 0 WHERE g.merchant_id = #{merchantId}
AND (g.goods_name LIKE CONCAT('%', #{keyword}, '%') OR g.keywords LIKE CONCAT('%', #{keyword}, '%'))
AND g.status = 1 AND g.audit_status = 1 AND g.is_deleted = 0 GROUP BY g.goods_id, g.cate_id, c.cate_name, g.merchant_id, m.merchant_name, g.goods_name, g.goods_intro, g.goods_pic, g.sell_count, g.comment_count, g.goods_score HAVING COUNT(s.sku_id) > 0 ORDER BY g.sell_count DESC, g.goods_id DESC LIMIT #{offset}, #{pageSize}
